// Build prompts for the 3-phase update process
const input = $input.first().json;

const { id, name, ip, type, ssh_user, ssh_password } = input;

// Proxmox host for LXC commands
const PROXMOX_HOST = '10.1.1.100';
const PROXMOX_USER = 'root';

const isLXC = type === 'lxc';

// Phase 1: Check LXC status and start if stopped
const check_prompt = isLXC
  ? `You are a Proxmox system administrator. Check if LXC container ${id} (${name}) is running and start it if stopped.

Execute via SSH on Proxmox host ${PROXMOX_HOST} as root:
1. Run: pct status ${id}
2. If status is "stopped", run: pct start ${id} && sleep 15
3. Report the original_state (running/stopped) and current_state

SSH credentials for Proxmox: ${PROXMOX_HOST}, user: ${PROXMOX_USER}
Respond with JSON: {"original_state": "running|stopped", "current_state": "running|stopped", "action_taken": "none|started", "success": true|false}`
  : `Check if system ${name} (${ip}) is reachable via SSH.
SSH: ${ip}, user: ${ssh_user}
Run: echo "ALIVE" && uptime
Respond with JSON: {"original_state": "running", "current_state": "running", "action_taken": "none", "success": true|false}`;

// Phase 2: Execute apt updates
const update_prompt = isLXC
  ? `Execute apt updates on LXC container ${id} (${name}) via Proxmox.
Run on Proxmox host ${PROXMOX_HOST}: pct exec ${id} -- bash -c "DEBIAN_FRONTEND=noninteractive apt-get update && apt-get -y upgrade && apt-get -y autoremove && apt-get clean"
Also check: pct exec ${id} -- bash -c "[ -f /var/run/reboot-required ] && echo REBOOT_NEEDED || echo NO_REBOOT"
Respond with JSON: {"packages_updated": <number>, "reboot_required": true|false, "update_output": "<summary>", "success": true|false, "errors": []}`
  : `Execute apt updates on system ${name} (${ip}) via direct SSH.
SSH: ${ip}, user: ${ssh_user}
Commands:
1. DEBIAN_FRONTEND=noninteractive apt-get update
2. apt-get -y upgrade
3. apt-get -y autoremove && apt-get clean
4. [ -f /var/run/reboot-required ] && echo REBOOT_NEEDED || echo NO_REBOOT
Respond with JSON: {"packages_updated": <number>, "reboot_required": true|false, "update_output": "<summary>", "success": true|false, "errors": []}`;

// Phase 3: Restore original state (only used if was stopped)
const restore_prompt = isLXC
  ? `Stop LXC container ${id} (${name}) on Proxmox host ${PROXMOX_HOST} to restore original stopped state.
Run: pct stop ${id}
Respond with JSON: {"action": "stopped", "success": true|false}`
  : `No restore needed for non-LXC system. Respond with JSON: {"action": "none", "success": true}`;

const system_prompt = 'You are an expert Linux/Proxmox system administrator. Execute the requested operations and respond ONLY with valid JSON. No markdown, no explanations.';

return [{
  json: {
    id, name, ip, type, ssh_user, ssh_password,
    check_prompt,
    update_prompt,
    restore_prompt,
    system_prompt,
    is_lxc: isLXC,
    proxmox_host: PROXMOX_HOST
  }
}];

// Parse check result and extract original_state
const response = $input.first().json;
const promptData = $('🔧 Build Update Prompts').first().json;

let checkResult = { original_state: 'running', current_state: 'running', action_taken: 'none', success: true };

try {
  const content = response.choices?.[0]?.message?.content || '{}';
  // Extract JSON from response (handle markdown code blocks)
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    checkResult = { ...checkResult, ...JSON.parse(jsonMatch[0]) };
  }
} catch (e) {
  checkResult.error = `Parse error: ${e.message}`;
}

return [{
  json: {
    ...promptData,
    check_result: checkResult,
    original_state: checkResult.original_state || 'running'
  }
}];

// Parse update result
const response = $input.first().json;
const prevData = $('🔧 Parse Check Result').first().json;

let updateResult = { packages_updated: 0, reboot_required: false, update_output: '', success: false, errors: [] };

try {
  const content = response.choices?.[0]?.message?.content || '{}';
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    updateResult = { ...updateResult, ...JSON.parse(jsonMatch[0]) };
  }
} catch (e) {
  updateResult.errors = [`Parse error: ${e.message}`];
}

return [{
  json: {
    ...prevData,
    update_result: updateResult
  }
}];

// Collect all results and build final output
const items = $input.all();
const data = items[0].json;

// Get data from previous nodes
const parseUpdateData = $('🔧 Parse Update Result').first().json;
const updateResult = parseUpdateData.update_result || {};
const checkResult = parseUpdateData.check_result || {};

// Determine overall status
let status = 'success';
if (!updateResult.success) status = 'failed';
else if (updateResult.errors && updateResult.errors.length > 0) status = 'partial';

// Was restore executed?
let restoreResult = null;
try {
  restoreResult = $('🤖 Claude: Restore Original State').first().json;
} catch (e) {
  // No restore was needed
}

return [{
  json: {
    name: parseUpdateData.name,
    id: parseUpdateData.id,
    type: parseUpdateData.type,
    ip: parseUpdateData.ip,
    status,
    packages_updated: updateResult.packages_updated || 0,
    reboot_required: updateResult.reboot_required || false,
    original_state: parseUpdateData.original_state,
    restored_to_original: parseUpdateData.original_state === 'stopped',
    details: {
      check: checkResult,
      update: updateResult,
      restore: restoreResult ? 'executed' : 'not_needed'
    }
  }
}];
